  "/en/interaction/post-blog": `[
  {
    "@context": "https://schema.org",
    "@type": "WebPage",
    "@id": "https://www.openeuler.openatom.cn/en/interaction/post-blog",
    "url": "https://www.openeuler.openatom.cn/en/interaction/post-blog",
    "name": "Instructions to Post a Blog | openEuler",
    "description": "Learn the step-by-step process of posting a blog, from drafting your content to publishing and promoting it.",
    "inLanguage": "en",
    "isPartOf": {
      "@type": "WebSite",
      "@id": "https://www.openeuler.openatom.cn/",
      "url": "https://www.openeuler.openatom.cn/",
      "name": "openEuler"
    },
    "breadcrumb": {
      "@id": "https://www.openeuler.openatom.cn/en/interaction/post-blog#breadcrumb"
    }
  },
  {
    "@context": "https://schema.org",
    "@type": "BreadcrumbList",
    "@id": "https://www.openeuler.openatom.cn/en/interaction/post-blog#breadcrumb",
    "itemListElement": [
      {
        "@type": "ListItem",
        "position": 1,
        "name": "Home",
        "item": "https://www.openeuler.openatom.cn/en/"
      },
      {
        "@type": "ListItem",
        "position": 2,
        "name": "Interaction",
        "item": "https://www.openeuler.openatom.cn/en/interaction/"
      },
      {
        "@type": "ListItem",
        "position": 3,
        "name": "Instructions to Post a Blog",
        "item": "https://www.openeuler.openatom.cn/en/interaction/post-blog"
      }
    ]
  },
  {
    "@context": "https://schema.org",
    "@type": "HowTo",
    "@id": "https://www.openeuler.openatom.cn/en/interaction/post-blog#howto",
    "name": "How to Post a Blog on openEuler",
    "description": "Learn the step-by-step process of posting a blog on the openEuler community, from account preparation to submitting a pull request.",
    "url": "https://www.openeuler.openatom.cn/en/interaction/post-blog",
    "inLanguage": "en",
    "step": [
      {
        "@type": "HowToSection",
        "name": "Preparation",
        "position": 1,
        "itemListElement": [
          {
            "@type": "HowToStep",
            "position": 1,
            "name": "Register an AtomGit account",
            "text": "Register an AtomGit account by following the instructions at http://git.mydoc.io/?t=179267."
          },
          {
            "@type": "HowToStep",
            "position": 2,
            "name": "Set your primary email in AtomGit",
            "text": "Set your primary mailbox in AtomGit settings at https://atomgit.com/setting/email."
          },
          {
            "@type": "HowToStep",
            "position": 3,
            "name": "Sign your CLA",
            "text": "Sign your Contributor License Agreement (CLA) at https://clasign.osinfra.cn/sign/6983225bdcbb19710248ccf0?lang=en."
          },
          {
            "@type": "HowToStep",
            "position": 4,
            "name": "Prepare your git environment",
            "text": "Set up your local git environment by following the guide at http://git.mydoc.io/?t=180692."
          }
        ]
      },
      {
        "@type": "HowToSection",
        "name": "Understand Blog Format",
        "position": 2,
        "itemListElement": [
          {
            "@type": "HowToStep",
            "position": 1,
            "name": "Learn the markdown blog format",
            "text": "The openEuler blog is written in Markdown format. Review the blog design at https://atomgit.com/openeuler/openEuler-portal/blob/master/app/en/interaction/post-blog/index.md. Each blog file requires a YAML front matter header with fields: title, date, category, tags, sig, archives, author, and summary."
          },
          {
            "@type": "HowToStep",
            "position": 2,
            "name": "Use the sample blog template",
            "text": "Copy the sample post from https://atomgit.com/openeuler/openEuler-portal/blob/master/app/en/interaction/post-blog/blog_example/20220901-sample-post.md to your folder and edit it as a starting point."
          }
        ]
      },
      {
        "@type": "HowToSection",
        "name": "Post Your Blog",
        "position": 3,
        "itemListElement": [
          {
            "@type": "HowToStep",
            "position": 1,
            "name": "Fork the openEuler blog project",
            "text": "Fork the openEuler portal project to your own AtomGit account. Refer to http://git.mydoc.io/?t=153749 for detailed guidance."
          },
          {
            "@type": "HowToStep",
            "position": 2,
            "name": "Clone the repository",
            "text": "Clone the forked repository to your local environment using: git clone https://atomgit.com/<your-atomgit-id>/openEuler-portal"
          },
          {
            "@type": "HowToStep",
            "position": 3,
            "name": "Create a new branch",
            "text": "Create a new branch for your blog post using: git checkout -b <branch-name>"
          },
          {
            "@type": "HowToStep",
            "position": 4,
            "name": "Create your blog folder and file",
            "text": "For an English blog, navigate to app/en/blog and create a folder named after your AtomGit ID. For a Chinese blog, use app/zh/blog as your work path. Create your blog markdown file inside this folder."
          },
          {
            "@type": "HowToStep",
            "position": 5,
            "name": "Submit a pull request",
            "text": "After writing your blog, commit and push your changes, then submit a pull request to the openEuler portal repository on AtomGit for review."
          }
        ]
      }
    ]
  }
]`,
