  "/zh/approve/approve-step": `[
  {
    "@context": "https://schema.org",
    "@type": "WebPage",
    "name": "openEuler OSV技术测评步骤",
    "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step",
    "description": "openEuler提供了完整的测试流程和工具，检测伙伴二次发行版生态核心特性不丢失，关键配置不更改，帮助牵引实现扩展仓库openEuler系共享、共用，主流行业应用在openEuler系不同的OSV生态复用度。",
    "inLanguage": "zh",
    "isPartOf": {
      "@type": "WebSite",
      "name": "openEuler社区",
      "url": "https://www.openeuler.openatom.cn"
    },
    "breadcrumb": {
      "@type": "BreadcrumbList",
      "itemListElement": [
        {
          "@type": "ListItem",
          "position": 1,
          "name": "openEuler社区",
          "item": "https://www.openeuler.openatom.cn/zh/"
        },
        {
          "@type": "ListItem",
          "position": 2,
          "name": "OSV技术测评列表",
          "item": "https://www.openeuler.openatom.cn/zh/approve/"
        },
        {
          "@type": "ListItem",
          "position": 3,
          "name": "OSV技术测评步骤",
          "item": "https://www.openeuler.openatom.cn/zh/approve/approve-step"
        }
      ]
    }
  },
  {
    "@context": "https://schema.org",
    "@type": "HowTo",
    "name": "openEuler OSV技术测评步骤",
    "description": "openEuler提供了完整的测试流程和工具，检测伙伴二次发行版生态核心特性不丢失，关键配置不更改，帮助牵引实现扩展仓库openEuler系共享、共用，主流行业应用在openEuler系不同的OSV生态复用度。",
    "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step",
    "inLanguage": "zh",
    "step": [
      {
        "@type": "HowToStep",
        "position": 1,
        "name": "申请加入openEuler社区",
        "text": "您需要在AtomGit平台申请加入openEuler社区，成为组织成员。申请地址：https://atomgit.com/openeuler/infrastructure/blob/master/docs/openEuler-Infra-FAQ.md",
        "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step#step1"
      },
      {
        "@type": "HowToStep",
        "position": 2,
        "name": "了解OSV技术测评策略",
        "text": "开展OSV技术测评之前，您需要了解OSV技术测评策略、测评标准，以及使用OSV技术测评工具进行自验证。地址如下：https://atomgit.com/openeuler/oecp",
        "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step#step2"
      },
      {
        "@type": "HowToStep",
        "position": 3,
        "name": "申请OSV技术测评",
        "text": "您需要向公共邮箱（compatibility@openeuler.io）发送OSV技术测评申请，邮件标题需要注明"申请OSV技术测评"。如您提交的是嵌入式OS，请额外提交测试报告。收到邮件后，openEuler团队中sig组会与您沟通进行协议签署。如果没有签署CLA，请先签署：https://clasign.osinfra.cn/sign/6983225bdcbb19710248ccf0",
        "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step#step3"
      },
      {
        "@type": "HowToStep",
        "position": 4,
        "name": "提交OSV技术测评申请issue",
        "text": "完成协议签署后，您需要在openEuler社区（https://atomgit.com/openeuler/oecp/issues）的OSV技术测评项目下创建issue，将所需要测评的操作系统信息在issue中明确，以及ISO镜像地址。openEuler团队会及时了解issue的信息，并提出建议。",
        "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step#step4"
      },
      {
        "@type": "HowToStep",
        "position": 5,
        "name": "OSV技术测评",
        "text": "openEuler社区会第一时间对提供的ISO进行OSV技术测评，测评之后会联系您进行部分结果确认以及审核，之后会将测评结果发布到openEuler官网上。",
        "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step#step5"
      },
      {
        "@type": "HowToStep",
        "position": 6,
        "name": "OSV技术测评结果发布",
        "text": "openEuler团队会针对提交结果进行审核，如果通过，会将OSV技术测评结果添加到OSV技术测评列表中。",
        "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step#step6"
      },
      {
        "@type": "HowToStep",
        "position": 7,
        "name": "openEuler官网首页LOGO展示",
        "text": "如果通过OSV技术测评，并已经在OSV技术测评列表（https://www.openeuler.openatom.cn/zh/approve）中展示，您可以联系openEuler社区（public@openeuler.io），在社区官网首页"发布openEuler商业发行版的厂商"栏目中展示贵组织单位的LOGO。邮件标题需注明"申请在openEuler社区官网首页展示logo"，并随附：贵组织单位的全称、业务负责人及业务对接人的姓名和邮箱、OSV技术测评通过结果及相关证明文件。",
        "url": "https://www.openeuler.openatom.cn/zh/approve/approve-step#step7"
      }
    ]
  }
]`,
  "/zh/community/charter": `{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "openEuler社区章程是什么？",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "openEuler社区章程（全称《openEuler项目群开源治理制度》）是规范openEuler开源社区运作的基本纲领，由openEuler委员会制定，经开放原子开源基金会审定后生效，最新版本修订于2024年3月。"
      }
    },
    {
      "@type": "Question",
      "name": "如何成为openEuler捐赠人？",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "通过与开放原子开源基金会签署《openEuler项目群专项资金捐赠协议》成为捐赠人。最低门槛为青铜捐赠人（2万元/年），最高为战略捐赠人（500万元/年，连续2年以上）。"
      }
    },
    {
      "@type": "Question",
      "name": "openEuler委员会委员如何产生？",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "战略、白金、黄金捐赠人各委派一名代表参加openEuler委员会，学术机构和非营利组织最多一名代表经常务委员会推荐并经全体委员三分之二以上表决通过后加入。"
      }
    },
    {
      "@type": "Question",
      "name": "openEuler社区的知识产权如何管理？",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "贡献到openEuler项目群的代码须以开源许可证发布，贡献者须签署原创声明或贡献协议（CLA）。知识产权管理符合开放原子开源基金会知识产权策略。"
      }
    },
    {
      "@type": "Question",
      "name": "openEuler委员会主席任期多长？",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "openEuler委员会主席每届任期2年，最多可连任两届（共4年），由常务委员会委员选举产生。"
      }
    },
    {
      "@type": "Question",
      "name": "如何在openEuler社区新建SIG？",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "在社区中找到2名以上有共同兴趣的人，确定SIG Maintainer，提交包含背景、业务范围和目标的SIG提案，经技术委员会评审通过后正式成立。"
      }
    }
  ]
}`,
